import { navigateStudio, pollAgentSessionEvents, } from "../agentSessionChannel.js";
import { getConfig, hasCredentials } from "../config.js";
const RESPONSE_TIMEOUT_MS = 12_000;
const args = process.argv.slice(2);
const sessionId = args[0];
const path = args[1];
if (!sessionId || !path) {
    console.error("Usage: navigateStudio <sessionId> <path>");
    process.exit(1);
}
if (!hasCredentials()) {
    console.error("Not authenticated.");
    process.exit(1);
}
const config = getConfig();
if (!config.apiKey) {
    console.error("No API key configured.");
    process.exit(1);
}
const client = {
    serviceUrl: config.serviceUrl,
    apiKey: config.apiKey,
    sessionId,
};
try {
    await navigateStudio(client, path);
}
catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    process.stdout.write(`${JSON.stringify({ event: "not-responding", sessionId, reason: message })}\n`);
    process.exit(1);
}
const abortController = new AbortController();
let responded = false;
const pollPromise = pollAgentSessionEvents({
    serviceUrl: config.serviceUrl,
    apiKey: config.apiKey,
    sessionId,
    abortSignal: abortController.signal,
    onEvent: (event) => {
        if (event.type === "studio:navigated") {
            responded = true;
            abortController.abort();
        }
        if (event.type === "studio:session-ended") {
            abortController.abort();
        }
    },
}).catch(() => { });
const timeout = new Promise((resolve) => setTimeout(resolve, RESPONSE_TIMEOUT_MS));
await Promise.race([pollPromise, timeout]);
abortController.abort();
if (responded) {
    process.stdout.write(`${JSON.stringify({ event: "navigated", sessionId, path })}\n`);
    process.exit(0);
}
else {
    process.stdout.write(`${JSON.stringify({ event: "not-responding", sessionId })}\n`);
    process.exit(1);
}
